"use client"

import { useEffect, useState } from 'react'

export default function UsersPage() {
  const [data, setData] = useState<any>(null)
  const [error, setError] = useState('')

  useEffect(() => {
    fetch('/api/admin/users', { credentials: 'include' })
      .then(async (res) => {
        if (!res.ok) throw new Error('加载失败')
        return res.json()
      })
      .then(setData)
      .catch(() => setError('暂时无法获取用户列表，请确认以 root 登录后访问。'))
  }, [])

  return (
    <div>
      <div className="header-row"><h2>用户管理</h2></div>
      <div className="table-wrap">
        {error ? <div>{error}</div> : !data ? <div>加载中…</div> : (
          <table>
            <thead><tr><th>ID</th><th>用户名</th><th>邮箱</th><th>手机</th><th>角色</th><th>设备数</th><th>注册时间</th></tr></thead>
            <tbody>
              {data.items.map((u: any) => (
                <tr key={u.id}><td>{u.id}</td><td>{u.username}</td><td>{u.email || '-'}</td><td>{u.phone || '-'}</td><td>{u.role}</td><td>{u.device_count}</td><td>{u.created_at}</td></tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  )
}
